pub(crate) fn normalize_issue_for_test(raw: &Value) -> Option<Issue> {
    normalize_issue(raw, None)
}

/// Expose normalization with assignee filter for testing.
#[cfg(test)]
pub(crate) fn normalize_issue_with_assignee_for_test(
    raw: &Value,
    assignee: Option<&str>,
) -> Option<Issue> {
    let filter = assignee.and_then(|a| {
        let trimmed = a.trim();
        if trimmed.is_empty() {
            None
        } else {
            let mut match_values = HashSet::new();
            match_values.insert(trimmed.to_string());
            Some(AssigneeFilter { match_values })
        }
    });
    normalize_issue(raw, filter.as_ref())
}
